"""Boyer-Moore-Horspool style exact string search with comparison counting."""

from __future__ import annotations

from dataclasses import dataclass
from typing import Dict, List


@dataclass(frozen=True)
class SearchResult:
    matches: List[int]
    comparisons: int


def build_bad_character_shift(pattern: str) -> Dict[str, int]:
    if pattern == "":
        return {}
    m = len(pattern)
    table = {ch: m for ch in set(pattern)}
    for idx, ch in enumerate(pattern[:-1]):
        table[ch] = m - 1 - idx
    return table


def boyer_moore_horspool(text: str, pattern: str) -> SearchResult:
    """Search with right-to-left comparisons and bad-character tail skips.

    ASSUMPTION: the original paper's static full Boyer-Moore tables are not
    reconstructed here; this implements the Horspool bad-character
    simplification to reproduce the core tail-comparison skip behavior.
    """
    if pattern == "":
        return SearchResult(list(range(len(text) + 1)), 0)

    n, m = len(text), len(pattern)
    if m > n:
        return SearchResult([], 0)

    shifts = build_bad_character_shift(pattern)
    matches: List[int] = []
    comparisons = 0
    i = 0
    while i <= n - m:
        j = m - 1
        while j >= 0:
            comparisons += 1
            if pattern[j] != text[i + j]:
                break
            j -= 1
        if j < 0:
            matches.append(i)
            i += shifts.get(text[i + m - 1], m) if i + m - 1 < n else 1
        else:
            i += shifts.get(text[i + m - 1], m)
    return SearchResult(matches, comparisons)


def naive_search(text: str, pattern: str) -> SearchResult:
    if pattern == "":
        return SearchResult(list(range(len(text) + 1)), 0)
    matches: List[int] = []
    comparisons = 0
    for i in range(0, len(text) - len(pattern) + 1):
        matched = True
        for j, ch in enumerate(pattern):
            comparisons += 1
            if text[i + j] != ch:
                matched = False
                break
        if matched:
            matches.append(i)
    return SearchResult(matches, comparisons)


def reference_find_all(text: str, pattern: str) -> List[int]:
    if pattern == "":
        return list(range(len(text) + 1))
    out: List[int] = []
    start = 0
    while True:
        idx = text.find(pattern, start)
        if idx == -1:
            return out
        out.append(idx)
        start = idx + 1

